import { useState, useEffect, useRef, useCallback, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { Languages, Loader2, RotateCcw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

/** Detect if text is predominantly Chinese */
function isChineseText(text: string): boolean {
  const chineseChars = text.match(/[\u4e00-\u9fff\u3400-\u4dbf]/g);
  const totalChars = text.replace(/\s/g, "").length;
  if (!chineseChars || totalChars === 0) return false;
  return chineseChars.length / totalChars > 0.6;
}

/** Detect the likely language of text based on character patterns */
function detectTextLang(text: string): string {
  if (isChineseText(text)) return "zh";
  if (/[\u3040-\u309f\u30a0-\u30ff]/.test(text)) return "ja";
  if (/[\uac00-\ud7af\u1100-\u11ff]/.test(text)) return "ko";
  if (/[\u0600-\u06ff]/.test(text)) return "ar";
  if (/[\u0400-\u04ff]/.test(text)) return "ru";
  if (/\b(como|este|esta|uma|não|são|também|através)\b/i.test(text)) return "pt";
  return "en";
}

const CACHE_VERSION = 3;
const translationCache = new Map<string, string>();

interface IChingSectionProps {
  /** The I Ching text (may be in any language) */
  text: string;
  /** Override display text (from parent's unified translation) */
  translatedText?: string | null;
  className?: string;
  /** If true, hide the label header */
  hideLabel?: boolean;
}

/**
 * I Ching display component.
 * Defaults to showing original text (Chinese). Users can manually translate
 * via an inline button. No auto-translation on mount.
 */
const IChingSection = ({ text, translatedText, className, hideLabel }: IChingSectionProps) => {
  const { t, i18n } = useTranslation();
  const userLang = i18n.language;
  const [manualTranslatedText, setManualTranslatedText] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [showTranslation, setShowTranslation] = useState(false);
  const lastText = useRef<string | null>(null);

  // Reset if text changes
  useEffect(() => {
    if (lastText.current !== text) {
      lastText.current = text;
      setManualTranslatedText(null);
      setShowTranslation(false);
    }
  }, [text]);

  // Display priority: parent override > manual translation > original
  const displayText = translatedText || (showTranslation ? manualTranslatedText : null) || text;

  const handleManualTranslate = async () => {
    // Toggle off if already showing
    if (showTranslation) {
      setShowTranslation(false);
      return;
    }

    // Skip if text already matches user's language
    const textLang = detectTextLang(text);
    if (textLang === userLang || (userLang === "zh" && isChineseText(text))) {
      toast.info(t("translate.alreadyInLanguage", "内容已是当前语言"));
      return;
    }

    const cacheKey = `iching_manual_v${CACHE_VERSION}_${userLang}_${text.substring(0, 100)}`;
    const cached = translationCache.get(cacheKey);
    if (cached) {
      setManualTranslatedText(cached);
      setShowTranslation(true);
      return;
    }

    setIsTranslating(true);
    try {
      const { data, error } = await supabase.functions.invoke("translate-content", {
        body: { text, targetLang: userLang },
      });
      if (!error && data?.translatedText) {
        translationCache.set(cacheKey, data.translatedText);
        setManualTranslatedText(data.translatedText);
        setShowTranslation(true);
      } else {
        toast.error(t("translate.error", "翻译失败，请稍后重试"));
      }
    } catch {
      toast.error(t("translate.error", "翻译失败，请稍后重试"));
    } finally {
      setIsTranslating(false);
    }
  };

  const label = t("iching.label", "I Ching Interpretation");

  return (
    <div className={className}>
      {!hideLabel && (
        <p className="text-xs font-medium text-muted-foreground mb-2 flex items-center gap-1.5">
          <span>☰</span>
          {label}
        </p>
      )}
      <p className="whitespace-pre-line text-sm leading-[1.8] text-foreground/80 italic">
        {displayText}
      </p>
      {/* Manual translate button */}
      {!translatedText && (
        <div className="flex justify-end mt-2">
          <button
            className={`inline-flex items-center gap-1 min-h-[28px] py-0.5 px-2 rounded-md text-xs font-medium transition-all duration-200 active:scale-95 ${
              isTranslating
                ? "text-muted-foreground cursor-wait"
                : showTranslation
                  ? "text-primary bg-primary/10"
                  : "text-muted-foreground hover:text-primary active:text-primary"
            }`}
            disabled={isTranslating}
            onClick={handleManualTranslate}
          >
            {isTranslating ? (
              <Loader2 className="h-3 w-3 animate-spin" />
            ) : showTranslation ? (
              <RotateCcw className="h-3 w-3" />
            ) : (
              <Languages className="h-3 w-3" />
            )}
            <span>
              {isTranslating
                ? t("translate.translating", "翻译中...")
                : showTranslation
                  ? t("translate.showOriginal", "显示原文")
                  : t("translate.button", "翻译")}
            </span>
          </button>
        </div>
      )}
    </div>
  );
};

export default IChingSection;

/**
 * Split long story text into safer chunks to avoid model truncation.
 */
const STORY_CHUNK_SIZE = 1800;

function splitStoryIntoChunks(text: string, maxChunkSize = STORY_CHUNK_SIZE): string[] {
  const normalized = text.replace(/\r\n/g, "\n").trim();
  if (!normalized) return [];
  if (normalized.length <= maxChunkSize) return [normalized];

  const blocks = normalized.split(/\n{2,}/).filter((b) => b.trim().length > 0);
  const chunks: string[] = [];
  let current = "";

  for (const rawBlock of blocks) {
    const block = rawBlock.trim();
    const candidate = current ? `${current}\n\n${block}` : block;

    if (candidate.length <= maxChunkSize) {
      current = candidate;
      continue;
    }

    if (current) {
      chunks.push(current);
      current = "";
    }

    if (block.length <= maxChunkSize) {
      current = block;
      continue;
    }

    for (let i = 0; i < block.length; i += maxChunkSize) {
      const part = block.slice(i, i + maxChunkSize).trim();
      if (part) chunks.push(part);
    }
  }

  if (current) chunks.push(current);
  return chunks;
}

async function translateInChunks(text: string, targetLang: string): Promise<string | null> {
  const chunks = splitStoryIntoChunks(text);
  if (chunks.length === 0) return null;

  const translatedParts: string[] = [];
  for (const chunk of chunks) {
    const { data, error } = await supabase.functions.invoke("translate-content", {
      body: { text: chunk, targetLang },
    });

    if (error || !data?.translatedText) {
      return null;
    }

    translatedParts.push(data.translatedText);
  }

  return translatedParts.join("\n\n");
}

/**
 * Exported helper: manual unified translation for narrative + I Ching.
 */
export function useStoryTranslation(buildingNarrative: string, iChingText: string) {
  const [translatedNarrative, setTranslatedNarrative] = useState<string | null>(null);
  const [translatedIChing, setTranslatedIChing] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [showTranslation, setShowTranslation] = useState(false);

  const translateStory = useCallback(async (targetLang: string): Promise<boolean> => {
    if (showTranslation) {
      setShowTranslation(false);
      return true;
    }

    const hasNarrative = !!buildingNarrative?.trim();
    const hasIChing = !!iChingText?.trim();
    if (!hasNarrative && !hasIChing) return false;

    const narrativeCacheKey = `story_narrative_v${CACHE_VERSION}_${targetLang}_${buildingNarrative.length}_${buildingNarrative.substring(0, 80)}`;
    const iChingCacheKey = `iching_translate_v${CACHE_VERSION}_${iChingText.substring(0, 100)}_${targetLang}`;

    let narrativeResult = hasNarrative ? translationCache.get(narrativeCacheKey) ?? null : null;
    let iChingResult = hasIChing ? translationCache.get(iChingCacheKey) ?? null : null;

    setIsTranslating(true);
    try {
      if (hasNarrative && !narrativeResult) {
        narrativeResult = await translateInChunks(buildingNarrative, targetLang);
        if (narrativeResult) translationCache.set(narrativeCacheKey, narrativeResult);
      }

      if (hasIChing && !iChingResult) {
        const { data, error } = await supabase.functions.invoke("translate-content", {
          body: { text: iChingText, targetLang },
        });

        if (!error && data?.translatedText) {
          iChingResult = data.translatedText;
          translationCache.set(iChingCacheKey, data.translatedText);
        }
      }

      if (hasNarrative && narrativeResult) setTranslatedNarrative(narrativeResult);
      if (hasIChing && iChingResult) setTranslatedIChing(iChingResult);

      const success = (!!narrativeResult || !hasNarrative) && (!!iChingResult || !hasIChing);
      if (success) setShowTranslation(true);
      return success;
    } catch {
      return false;
    } finally {
      setIsTranslating(false);
    }
  }, [buildingNarrative, iChingText, showTranslation]);

  return {
    narrativeDisplay: showTranslation ? translatedNarrative : null,
    iChingDisplay: showTranslation ? translatedIChing : null,
    translateStory,
    isTranslating,
    showTranslation,
  };
}

/**
 * Hook to auto-translate narrative text to user's UI language on mount.
 */
export function useAutoTranslateNarrative(narrative: string | null, userLang: string) {
  const [translated, setTranslated] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const attempted = useRef(false);
  const lastNarrative = useRef<string | null>(null);

  useEffect(() => {
    if (!narrative) { setTranslated(null); return; }
    
    // Reset if narrative changed
    if (lastNarrative.current !== narrative) {
      attempted.current = false;
      lastNarrative.current = narrative;
    }
    if (attempted.current) return;

    // Skip if user's language is Chinese (narrative often has Chinese as native)
    // But also skip if the narrative already seems to match user's language
    const isChinese = isChineseText(narrative);
    if (userLang === "zh" && isChinese) { setTranslated(null); return; }
    // If narrative is in Latin script and user is en/pt, check if it's already in that language
    // We can't perfectly detect, so always translate to ensure correct language
    if (userLang === "zh" && !isChinese) {
      // Translate to Chinese
    }

    const targetLang = userLang;
    const cacheKey = `narrative_auto_v${CACHE_VERSION}_${narrative.substring(0, 100)}_${targetLang}`;
    const cached = translationCache.get(cacheKey);
    if (cached) {
      setTranslated(cached);
      attempted.current = true;
      return;
    }

    attempted.current = true;
    setIsLoading(true);
    supabase.functions
      .invoke("translate-content", { body: { text: narrative, targetLang } })
      .then(({ data, error }) => {
        if (!error && data?.translatedText) {
          translationCache.set(cacheKey, data.translatedText);
          setTranslated(data.translatedText);
        }
      })
      .catch(() => { /* keep original */ })
      .finally(() => setIsLoading(false));
  }, [narrative, userLang]);

  return { translatedNarrative: translated, isAutoTranslating: isLoading };
}
